@app.route('/logout', methods=['POST'])
@require_auth
def logout():
    session_token = request.headers.get('Authorization', '').replace('Bearer ', '')
    
    with get_db() as conn:
        conn.execute(
            'DELETE FROM sessions WHERE session_token = ?',
            (session_token,)
        )
        conn.commit()
    
    return jsonify({'message': 'Logged out successfully'}), 200

